### 7. Input / Response 데이터 클래스

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileDto.kt`

```kotlin
// GraphQL Input (스키마와 필드명 1:1 매핑)
data class UpdateUserProfileInput(
    val nickname: String?,
    val bio: String?,
    val profileImageUrl: String?,
    val birthDate: String?,
    val gender: Gender?,
    val mbti: Mbti?,
    val voiceIntroUrl: String?,
    val interests: List<String>?,
    val height: Int?,
    val job: String?,
    val location: String?,
)

// GraphQL Response
data class UserProfileResponse(
    val userId: String,
    val nickname: String,
    val bio: String?,
    val profileImageUrl: String?,
    val birthDate: String?,
    val gender: Gender?,
    val mbti: Mbti?,
    val voiceIntroUrl: String?,
    val interests: List<String>,
    val height: Int?,
    val job: String?,
    val location: String?,
    val updatedAt: String,
)

// Proto -> Response 변환 확장 함수
fun com.maum.backend.protobuf.user.UserProfile.toResponse() = UserProfileResponse(
    userId           = userId,
    nickname         = nickname,
    bio              = bio.ifEmpty { null },
    profileImageUrl  = profileImageUrl.ifEmpty { null },
    birthDate        = birthDate.ifEmpty { null },
    gender           = if (gender == Gender.GENDER_UNSPECIFIED) null else gender.toGraphQL(),
    mbti             = if (mbti == Mbti.MBTI_UNSPECIFIED) null else mbti.toGraphQL(),
    voiceIntroUrl    = voiceIntroUrl.ifEmpty { null },
    interests        = interestsList,
    height           = if (height == 0) null else height,
    job              = job.ifEmpty { null },
    location         = location.ifEmpty { null },
    updatedAt        = updatedAt,
)
```

